INSERT INTO `questions` VALUES (1,1,'Apakah [Nama] secara konsisten mencerminkan misi IB dan profil pelajar dalam kepemimpinannya, sehingga setiap keputusan sekolah memperkuat nilai-nilai IB dan mendorong kemandirian siswa maupun guru?','Has [Name] demonstrated strong alignment with the IB mission and learner profile in administrative philosophy and practice, ensuring schoolwide decisions reflect IB values and empower both student and teacher agency?'),(2,2,'Apakah [Nama] telah merumuskan dan mengomunikasikan rencana strategis yang jelas dan berkelanjutan untuk pengembangan program IB, dengan memperlihatkan wawasan visioner dan kemampuan beradaptasi terhadap perkembangan pendidikan ke depan?','Has [Name] developed and articulated a clear, sustainable strategic plan for programme growth, guiding long-term improvement while demonstrating visionary thinking and adaptability to future educational trends?'),(3,3,'Apakah [Nama] mampu menjaga tujuan sekolah yang jelas dan konsisten sebagai pegangan praktik guru dan pengambilan keputusan, serta menjadi teladan kepemimpinan berprinsip yang selalu terbuka terhadap refleksi dan perbaikan?','Has [Name] maintained clear, consistent schoolwide goals that anchor teacher practice and institutional decision-making over time, modeling principled leadership and a commitment to continuous reflection?'),(4,4,'Apakah [Nama] menyampaikan harapan, jadwal, dan keputusan strategis dengan jelas, konsisten, dan transparan, serta membangun suasana di mana dialog terbuka dan mendengarkan secara aktif benar-benar terjadi?','Has [Name] communicated expectations, timelines, and strategic decisions with exceptional clarity, consistency, and transparency, fostering an environment of open dialogue and active listening?'),(5,5,'Apakah [Nama] berhasil membangun lingkungan profesional yang kolaboratif dan inklusif, di mana guru merasa dihargai, didengar, dan bebas berbagi gagasan baru serta sudut pandang yang beragam?','Has [Name] fostered a highly collaborative and inclusive professional environment where teachers feel valued, heard, and encouraged to share innovative ideas and diverse perspectives?'),(6,6,'Apakah [Nama] aktif mendukung pertumbuhan guru melalui akses yang merata terhadap pengembangan profesional IB yang bermakna, serta menjadi teladan sebagai pemelajar sepanjang hayat yang penuh rasa ingin tahu?','Has [Name] championed teacher growth by providing equitable access to meaningful IB professional development, and actively participated as a lifelong learner to model intellectual curiosity?'),(7,7,'Apakah [Nama] secara sungguh-sungguh menegakkan kebijakan IB dan menumbuhkan budaya integritas akademik di seluruh sekolah, dengan selalu berlandaskan kejujuran, etika, dan keadilan dalam setiap tindakan kepemimpinannya?','Has [Name] ensured rigorous adherence to IB policies and embedded a culture of academic integrity, acting consistently with honesty, ethics, and fairness in all leadership actions?'),(8,8,'Apakah [Nama] selalu hadir dan mudah ditemui di lingkungan sekolah, serta tanggap dan responsif terhadap kebutuhan keseharian guru, siswa, maupun orang tua?','Has [Name] maintained a consistent, approachable presence across the school community, remaining accessible and highly responsive to the daily realities of teachers, students, and parents?'),(9,9,'Apakah [Nama] mengambil keputusan yang tepat waktu, logis, dan berbasis bukti, serta menjelaskan alasan di baliknya secara terbuka agar seluruh staf memahami tujuan dan arah dari setiap perubahan yang dilakukan?','Has [Name] made timely, logical, and evidence-based decisions, communicating the underlying rationale clearly to ensure staff understand the purpose and vision behind organisational changes?'),(10,10,'Apakah [Nama] memberikan umpan balik yang membangun, penuh hormat, dan dapat langsung ditindaklanjuti, sehingga benar-benar mendukung pertumbuhan profesional guru secara adil dan setara?','Has [Name] provided constructive, respectful, and highly actionable feedback that meaningfully supports teacher professional growth while maintaining strict equity and fairness?'),(11,11,'Apakah [Nama] menyusun jadwal yang realistis dan terstruktur serta memastikan kelancaran operasional sehari-hari, dengan senantiasa memperhatikan dan menjaga keseimbangan antara beban kerja dan kesejahteraan guru?','Has [Name] created realistic, well-structured timelines and ensured smooth daily operations, demonstrating a balanced approach that actively respects and manages teacher workload and wellbeing?'),(12,12,'Apakah [Nama] mengelola dan mengalokasikan sumber daya serta fasilitas sekolah secara strategis untuk mendukung pembelajaran berbasis inkuiri dan memenuhi kebutuhan beragam warga sekolah secara optimal?','Has [Name] strategically allocated and managed instructional resources and school facilities to optimally support inquiry-based learning and the diverse needs of the school community?'),(13,13,'Apakah [Nama] menerapkan kebijakan sekolah dan IB secara konsisten, sungguh-sungguh, dan adil kepada seluruh staf, serta secara aktif mencegah kebingungan maupun kesan adanya keberpihakan?','Has [Name] applied school and IB policies with fidelity, consistency, and fairness across all staff members, proactively avoiding confusion or any perception of bias?'),(14,14,'Apakah [Nama] merespons permasalahan sistemik maupun operasional yang berdampak pada proses belajar mengajar secara cepat dan efektif, dengan menunjukkan inisiatif yang proaktif dan keteguhan dalam menghadapi tantangan?','Has [Name] responded promptly and effectively to systemic or daily issues affecting teaching and learning, demonstrating proactive problem-solving initiative and resilience in the face of challenges?'),(15,15,'Apakah [Nama] menunjukkan empati yang tulus dan secara nyata mendukung guru baik secara profesional maupun emosional, sehingga tercipta lingkungan kerja yang positif, aman, dan seimbang?','Has [Name] demonstrated deep empathy and actively supported teachers both professionally and emotionally, cultivating a positive, safe, and balanced work environment?'),(16,16,'Apakah [Nama] secara konsisten membangun struktur yang memberdayakan siswa untuk belajar secara aktif dan berbasis inkuiri, serta mendorong mereka untuk mengambil peran kepemimpinan dan bertindak secara bermakna dalam komunitas?','Has [Name] systematically promoted structures that empower student-centred, inquiry-based learning, encouraging students to take meaningful action and leadership roles within the community?'),(17,17,'Apakah [Nama] secara konsisten mengapresiasi kerja keras guru dan merayakan pencapaian profesional mereka dengan cara yang tulus, peka terhadap budaya, dan mampu membangkitkan semangat?','Has [Name] consistently acknowledged teacher effort and celebrated professional achievements in a meaningful, culturally responsive, and motivating manner?'),(18,18,'Apakah [Nama] membangun kepercayaan melalui perlakuan yang adil, tindakan yang transparan, dan komitmen yang teguh terhadap etika profesional?','Has [Name] built trust through equitable treatment, transparent actions, and consistent adherence to professional ethics?'),(19,19,'Apakah [Nama] mendukung sistem dan struktur yang mampu merespons keberagaman kebutuhan belajar siswa, sehingga setiap siswa mendapatkan pendampingan yang sesuai dan tepat waktu?','Has [Name] supported structures and systems that address diverse learning needs, ensuring students receive appropriate and timely interventions?'),(20,20,'Apakah [Nama] mencerminkan misi IB dan profil pelajar dalam filosofi dan praktik mengajarnya, serta menunjukkan keterlibatan yang mendalam dengan bacaan, gagasan, isu terkini, dan dinamika perilaku siswa?','Has [Name] demonstrated alignment with the IB mission and learner profile in teaching philosophy and practice, engaging with books, ideas, current issues, and student behaviour with depth and insight?'),(21,21,'Apakah [Nama] mendukung pembelajaran bahasa, termasuk bahasa ibu dan bahasa Inggris, sambil menyambut perspektif yang beragam untuk memperkaya pembelajaran di kelas dan pemahaman komunitas?','Has [Name] supported language learning, including both mother tongue and additional languages, while welcoming diverse perspectives to enrich classroom learning and community understanding?'),(22,22,'Apakah [Nama] aktif berinteraksi dengan komunitas yang lebih luas untuk menumbuhkan tanggung jawab sosial dan semangat kewarganegaraan global, serta mendorong siswa untuk berinisiatif dan memimpin dengan penuh tujuan dan semangat pengabdian?','Has [Name] engaged with the wider community to promote responsible action and global citizenship, empowering students to take initiative and lead with purpose and service?'),(23,23,'Apakah [Nama] membangun budaya kolaboratif melalui interaksi profesional yang teratur dan bermakna, mendorong kerja tim dan pembelajaran bersama di antara siswa dan sesama guru dan staf sekolah lainnya?','Has [Name] fostered a collaborative culture through regular and meaningful professional interactions, promoting teamwork and shared learning among students and colleagues?'),(24,24,'Apakah [Nama] aktif mengikuti dan menerapkan pengembangan profesional sesuai standar IB, serta menjunjung tinggi kejujuran, etika, dan keadilan dalam kesehariannya?','Has [Name] participated in and applied professional development aligned with IB expectations, while acting consistently with honesty, ethics, and fairness?'),(25,25,'Apakah [Nama] menjalankan kebijakan sekolah dengan sungguh-sungguh dan turut berkontribusi pada penyempurnaannya, serta menunjukkan keluwesan dan ketangguhan dalam menghadapi perubahan?','Has [Name] implemented school policies with fidelity and contributed to their ongoing refinement, responding flexibly to change and modeling resilience?'),(26,26,'Apakah [Nama] mengembangkan rencana kegiatan pembelajaran yang selaras dengan persyaratan IB dan mempromosikan pengajaran yang inovatif, mendorong kreativitas, rasa ingin tahu, dan pemikiran segar?','Has [Name] developed curriculum plans that align with IB requirements and promote innovative teaching, encouraging creativity, curiosity, and fresh thinking?'),(27,27,'Apakah [Nama] mengintegrasikan keterkaitan lintas disiplin â€” termasuk TOK dan konteks global â€” serta mengolah informasi secara bijak untuk membimbing siswa agar mampu berpikir secara mandiri dan kritis?','Has [Name] integrated interdisciplinary connections, including TOK and global contexts, analysing information thoughtfully to guide students in independent thinking?'),(28,28,'Apakah [Nama] merefleksikan dan merevisi kegiatan pembelajaran berdasarkan umpan balik siswa dan persyaratan program, dengan komunikasi yang jelas dan mendengarkan secara aktif untuk membangun dialog yang bermakna?','Has [Name] reflected on and revised curriculum based on student feedback and programme requirements, with clear communication and active listening to build meaningful dialogue?'),(29,29,'Apakah [Nama] menggunakan pendekatan berbasis inkuiri untuk menumbuhkan rasa ingin tahu, keterlibatan, dan rasa kepemilikan belajar siswa, serta membimbing mereka untuk berpikir secara mandiri dan kritis?','Has [Name] used inquiry-based strategies to foster student curiosity, engagement, and ownership, guiding students to think independently and critically?'),(30,30,'Apakah [Nama] mendifferensiasi pembelajaran untuk memenuhi kebutuhan beragam seluruh peserta didik secara efektif, sambil mendukung kesejahteraan siswa?','Has [Name] differentiated instruction to effectively address the diverse needs of all learners, while supporting student well-being and modelling a healthy, purposeful lifestyle?'),(31,31,'Apakah [Nama] memberikan dukungan yang konsisten dan terpadu untuk pengembangan kemampuan berbahasa di berbagai mata pelajaran, sambil berkomunikasi dengan jelas dan merangkul keberagaman perspektif siswa?','Has [Name] provided consistent and embedded support for language development across subjects, communicating clearly while embracing diverse perspectives?'),(32,32,'Apakah [Nama] mempromosikan dan menilai atribut profil pelajar IB sebagai bagian dari pengalaman belajar sehari-hari, memodelkan keterbukaan pikiran, integritas, dan keseimbangan sebagai bagian dari pertumbuhan holistik, serta menjadi teladan gaya hidup yang sehat dan penuh tujuan?','Has [Name] promoted and assessed IB learner profile attributes as part of daily learning experiences, modelling open-mindedness, integrity, and balance as part of holistic growth?'),(33,33,'Apakah [Nama] menerapkan kriteria dan praktik penilaian IB secara konsisten untuk menghasilkan evaluasi yang autentik dan relevan, dengan tetap mengedepankan pemikiran kritis dan integritas dalam setiap keputusan?','Has [Name] applied IB assessment criteria and practices to ensure authentic and aligned evaluation, while demonstrating critical thinking and ethical decision-making?'),(34,34,'Apakah [Nama] memfasilitasi kegiatan refleksi siswa sebagai bagian yang rutin dan bermakna dari proses pembelajaran, sehingga menumbuhkan jiwa kepemimpinan dan rasa memiliki tujuan dalam diri peserta didik?','Has [Name] facilitated student reflection as a meaningful and routine part of the learning process, encouraging leadership and a sense of purpose in learners?'),(35,35,'Apakah [Nama] memanfaatkan data penilaian sebagai dasar pengambilan keputusan pembelajaran dan peningkatan hasil belajar siswa, dengan menunjukkan kemampuan analisis yang tajam dan inovatif terhadap bukti-bukti yang ada?','Has [Name] used assessment data to inform instruction and improve student learning outcomes, demonstrating high-level literacy and innovation in analysing evidence?');
/*!40000 ALTER TABLE `questions` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `responses`
--

DROP TABLE IF EXISTS `responses`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `responses` (
  `id` int NOT NULL AUTO_INCREMENT,
  `assignment_id` int NOT NULL,
  `question_id` int NOT NULL,
  `grade` tinyint NOT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `is_test` tinyint(1) DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_response` (`assignment_id`,`question_id`),
  KEY `question_id` (`question_id`),
  CONSTRAINT `responses_ibfk_1` FOREIGN KEY (`assignment_id`) REFERENCES `assignments` (`id`) ON DELETE CASCADE,
  CONSTRAINT `responses_ibfk_2` FOREIGN KEY (`question_id`) REFERENCES `questions` (`id`),
  CONSTRAINT `responses_chk_1` CHECK ((`grade` between 1 and 4))
) ENGINE=InnoDB AUTO_INCREMENT=67126 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `responses`
--

